"""sklearn.cross_decomposition — Partial Least Squares and CCA."""
import numpy as np
from sklearn.base import BaseEstimator, RegressorMixin, TransformerMixin


class PLSRegression(BaseEstimator, RegressorMixin, TransformerMixin):
    """PLS Regression (PLS2 algorithm).

    Parameters
    ----------
    n_components : int, default=2
    max_iter : int, default=500
    tol : float, default=1e-6
    """

    def __init__(self, n_components=2, max_iter=500, tol=1e-6):
        self.n_components = n_components
        self.max_iter = max_iter
        self.tol = tol

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if y.ndim == 1:
            y = y.reshape(-1, 1)
        self.x_mean_ = X.mean(axis=0)
        self.y_mean_ = y.mean(axis=0)
        self.x_std_ = X.std(axis=0)
        self.x_std_[self.x_std_ == 0] = 1.0
        self.y_std_ = y.std(axis=0)
        self.y_std_[self.y_std_ == 0] = 1.0

        Xk = (X - self.x_mean_) / self.x_std_
        Yk = (y - self.y_mean_) / self.y_std_

        T, U, W, P, Q = [], [], [], [], []
        for _ in range(self.n_components):
            # NIPALS
            u = Yk[:, 0:1]
            for _it in range(self.max_iter):
                w = Xk.T @ u / (u.T @ u + 1e-15)
                w /= np.linalg.norm(w) + 1e-15
                t = Xk @ w
                q = Yk.T @ t / (t.T @ t + 1e-15)
                u_new = Yk @ q / (q.T @ q + 1e-15)
                if np.linalg.norm(u_new - u) < self.tol:
                    break
                u = u_new
            p = Xk.T @ t / (t.T @ t + 1e-15)
            Xk = Xk - t @ p.T
            Yk = Yk - t @ q.T
            T.append(t)
            U.append(u)
            W.append(w)
            P.append(p)
            Q.append(q)

        self.x_weights_ = np.hstack(W)
        self.x_loadings_ = np.hstack(P)
        self.y_loadings_ = np.hstack(Q)
        self.x_scores_ = np.hstack(T)
        # Regression coefficients
        W_mat = self.x_weights_
        P_mat = self.x_loadings_
        Q_mat = self.y_loadings_
        self.coef_ = W_mat @ np.linalg.pinv(P_mat.T @ W_mat) @ Q_mat.T
        self.coef_ = (self.coef_ * self.y_std_) / self.x_std_.reshape(-1, 1)
        self.intercept_ = self.y_mean_ - self.x_mean_ @ self.coef_
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        return X @ self.coef_ + self.intercept_

    def transform(self, X):
        X = np.asarray(X, dtype=float)
        Xc = (X - self.x_mean_) / self.x_std_
        return Xc @ self.x_weights_ @ np.linalg.pinv(self.x_loadings_.T @ self.x_weights_)


class CCA(PLSRegression):
    """Canonical Correlation Analysis (CCA).

    Simplified implementation based on PLS with CCA deflation.
    Uses the same NIPALS approach as PLS.

    Parameters
    ----------
    n_components : int, default=2
    max_iter : int, default=500
    tol : float, default=1e-6
    """
    pass
